mapper.select:
SELECT l.line_id AS lineId, l.line_name AS lineName,
/* 라인 자체 상태: ACTIVE / INACTIVE / (NULL은 INACTIVE 간주) */ UPPER(IFNULL(l.status, 'INACTIVE')) AS lineStatus,
/* 🔥 비활성 우선: 라인이 INACTIVE(또는 NULL)이면 무조건 INACTIVE */ CASE WHEN UPPER(IFNULL(l.status, 'INACTIVE')) = 'INACTIVE' THEN 'INACTIVE' WHEN EXISTS(SELECT 1 FROM work_order w WHERE w.line_id = l.line_id AND w.status = 'IN_PROGRESS' AND IFNULL(w.is_deleted,0) = 0) THEN 'IN_PROGRESS' WHEN EXISTS(SELECT 1 FROM work_order w WHERE w.line_id = l.line_id AND w.status = 'READY' AND IFNULL(w.is_deleted,0) = 0) THEN 'READY' WHEN EXISTS(SELECT 1 FROM work_order w WHERE w.line_id = l.line_id AND w.status = 'WAITING' AND IFNULL(w.is_deleted,0) = 0) THEN 'WAITING' ELSE 'IDLE' END AS state,
/* 대표 지시: 비활성 이면 NULL */ CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN NULL ELSE (SELECT w.order_id FROM work_order w WHERE w.line_id = l.line_id AND w.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w.is_deleted,0) = 0 ORDER BY FIELD(w.status,'IN_PROGRESS','READY','WAITING'), w.due_date ASC LIMIT 1) END AS workOrderId,
CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN NULL ELSE (SELECT w.product_id FROM work_order w WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) END AS productId,
CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN NULL ELSE (SELECT p.product_name FROM product p JOIN work_order w ON w.product_id = p.product_id WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) END AS productName,
CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN NULL ELSE (SELECT w.order_qty FROM work_order w WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) END AS orderQty,
CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN NULL ELSE (SELECT w.due_date FROM work_order w WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) END AS dueDate,
/* 누적 양품: 비활성 0 */ CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN 0 ELSE (SELECT COALESCE(SUM(pr.actual_qty - pr.defect_qty), 0) FROM production_result pr WHERE pr.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) END AS producedQty,
/* 진행률: 비활성 0, 0으로 나누기 방지 */ CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN 0 WHEN (SELECT w.order_qty FROM work_order w WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) > 0 THEN 100.0 * (SELECT COALESCE(SUM(pr.actual_qty - pr.defect_qty), 0) FROM production_result pr WHERE pr.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) / (SELECT w.order_qty FROM work_order w WHERE w.order_id = ( SELECT w2.order_id FROM work_order w2 WHERE w2.line_id = l.line_id AND w2.status IN ('IN_PROGRESS','READY','WAITING') AND IFNULL(w2.is_deleted,0) = 0 ORDER BY FIELD(w2.status,'IN_PROGRESS','READY','WAITING'), w2.due_date ASC LIMIT 1)) ELSE 0 END AS progressRate,
/* 대기건수: 비활성 0 */ CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN 0 ELSE (SELECT COUNT(*) FROM work_order w WHERE w.line_id = l.line_id AND w.status = 'READY' AND IFNULL(w.is_deleted,0) = 0) END AS readyCount,
CASE WHEN UPPER(IFNULL(l.status,'INACTIVE')) = 'INACTIVE' THEN 0 ELSE (SELECT COUNT(*) FROM work_order w WHERE w.line_id = l.line_id AND w.status = 'WAITING' AND IFNULL(w.is_deleted,0) = 0) END AS waitingCount
FROM production_line l ORDER BY l.line_id LIMIT 3
